// CPU-bound work to exercise FOIL hot loop
function computeWork(n: number): number {
  let result = 0;
  for (let i = 0; i < n; i++) {
    result += Math.sqrt(i) * Math.sin(i) * Math.cos(i);
  }
  return result;
}

async function loadUser(userId: string): Promise<string> {
  // Compute work proportional to userId hash
  const hash = userId.charCodeAt(0) + userId.length;
  const work = computeWork((hash % 100) * 100);
  return `${userId}:user:${work.toFixed(2)}`;
}

async function loadProfile(userId: string): Promise<string> {
  // Compute work
  const hash = userId.charCodeAt(userId.length - 1) + userId.length;
  const work = computeWork((hash % 100) * 100);
  return `${userId}:profile:${work.toFixed(2)}`;
}

function merge(user: string, profile: string): string {
  // Additional work in merge
  const merged = `${user}|${profile}`;
  const hash = merged.split('').reduce((h, c) => h + c.charCodeAt(0), 0);
  return `${merged}:${hash}`;
}

/**
 * Handles the gnosis app workflow.
 */
export async function app(input: { userId: string }): Promise<string> {
  const [user, profile] = await Promise.all([
    loadUser(input.userId),
    loadProfile(input.userId),
  ]);
  const summary = merge(user, profile);
  return summary;
}
